import React, { useEffect, useRef, useState } from "react";
import {
  MapContainer,
  TileLayer,
  Marker,
  useMap,
  CircleMarker
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "leaflet-routing-machine";
import "leaflet-routing-machine/dist/leaflet-routing-machine.css";

/* ICONS */
const userIcon = new L.DivIcon({
  className: "user-marker",
  html: `<div class="dot"></div>`,
});

const destIcon = new L.DivIcon({
  className: "dest-marker",
  html: "📍",
});

/* FOLLOW USER */
function FollowUser({ origin }) {
  const map = useMap();

  useEffect(() => {
    if (origin?.lat && origin?.lng) {
      map.flyTo([origin.lat, origin.lng], 16);
    }
  }, [origin]);

  return null;
}

/* SAFE ROUTING */
function Routing({ origin, destination, setInfo }) {
  const map = useMap();
  const routingRef = useRef(null);

  useEffect(() => {
    if (!origin || !destination || !map) return;

    try {
      if (routingRef.current) {
        map.removeControl(routingRef.current);
      }
    } catch { }

    const control = L.Routing.control({
      waypoints: [
        L.latLng(origin.lat, origin.lng),
        L.latLng(destination.lat, destination.lng),
      ],
      router: L.Routing.osrmv1({
        serviceUrl: "https://router.project-osrm.org/route/v1",
      }),
      lineOptions: {
        styles: [{ color: "blue", weight: 6 }],
      },
      addWaypoints: false,
      draggableWaypoints: false,
      createMarker: () => null,
      show: false,
    });

    control.on("routesfound", (e) => {
      const route = e.routes[0];

      const distance = (route.summary.totalDistance / 1000).toFixed(2);
      const time = (route.summary.totalTime / 60).toFixed(0);

      setInfo({ distance, time });
    });

    control.addTo(map);
    routingRef.current = control;

    return () => {
      try {
        if (routingRef.current) {
          map.removeControl(routingRef.current);
        }
      } catch { }
    };

  }, [origin, destination]);

  return null;
}

/* MAIN */
function MapView({ origin, destination, setInfo }) {
  const [search, setSearch] = useState("");

  /* SEARCH */
  const handleSearch = async () => {
    if (!search) return;

    try {
      const res = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${search}`
      );

      const data = await res.json();

      if (data.length === 0) {
        alert("Location not found");
        return;
      }

      const coords = {
        lat: parseFloat(data[0].lat),
        lng: parseFloat(data[0].lon),
      };

      window.setDestinationFromSearch(coords);
    } catch {
      alert("Search failed");
    }
  };

  if (!origin) return <p>📍 Loading map...</p>;

  return (
    <div className="map-app">

      {/* SEARCH */}
      <div className="map-search">
        <input
          placeholder="Search destination..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSearch()}
        />
      </div>

      {/* MAP */}
      <MapContainer
        center={[origin.lat, origin.lng]}
        zoom={15}
        className="map-full"
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        <Marker position={[origin.lat, origin.lng]} icon={userIcon} />

        <CircleMarker center={[origin.lat, origin.lng]} radius={20} />

        {destination && (
          <Marker
            position={[destination.lat, destination.lng]}
            icon={destIcon}
          />
        )}

        <FollowUser origin={origin} />

        {destination && (
          <Routing
            origin={origin}
            destination={destination}
            setInfo={setInfo}
          />
        )}
      </MapContainer>
      <div className="location-card glass">

        <h3>📍 Journey Details</h3>

        <div className="loc-row">
          <p><strong>Current Location:</strong></p>
          <span>
            {currentAddress || "Fetching location..."}
          </span>
        </div>

        <div className="loc-row">
          <p><strong>Destination:</strong></p>
          <span>
            {destAddress || "Not selected"}
          </span>
        </div>

      </div>
    </div>
  );
}

export default MapView;
